html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Animated Counter</title>
    <link rel="stylesheet" href="style.css">
</head>
<body>
    <div class="container mx-auto p-4">
        <h1 class="text-3xl font-bold mb-4">Animated Counter</h1>
        <div class="flex justify-center mb-4">
            <p id="counter" class="text-5xl font-bold">0</p>
        </div>
        <div class="flex justify-center">
            <button id="increment" class="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded">Increment</button>
            <button id="decrement" class="bg-red-500 hover:bg-red-700 text-white font-bold py-2 px-4 rounded ml-4">Decrement</button>
        </div>
    </div>
    <script src="script.js"></script>
</body>
</html>
